SELECT AVG(gpa) AS average_first_class_gpa
FROM students
WHERE classification = 'First Class';

SELECT AVG(gpa) AS average_gpa
FROM students
WHERE classification = 'First Class';

SELECT AVG(gpa) AS average_gpa_first_class_distinction
FROM students
WHERE classification = 'First Class with Distinction';

SELECT AVG(average_gpa) AS average_gpa
FROM graduation_statistics
WHERE batch = '0';

SELECT average_gpa
FROM graduation_statistics
WHERE batch = '0';

SELECT batch, total_graduates AS number_of_graduates, average_gpa
FROM graduation_statistics
GROUP BY batch;

SELECT first_name, last_name
FROM students
WHERE strftime('%Y', graduation_date) = '2018';

SELECT AVG(gpa) AS average_gpa
FROM students
WHERE classification IN ('First Class', 'First Class with Distinction');

SELECT AVG(gpa) AS avg_gpa
FROM students
WHERE classification = 'First Class with Distinction';

SELECT batch, MAX(gpa) AS highest_gpa
FROM students
GROUP BY batch;

SELECT batch, total_students, total_graduates, average_gpa
FROM graduation_statistics
ORDER BY batch;
